import React, { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../../api/axios";

const initialAppointment = {
  lead: "",
  vehicle: "",
  appointmentType: "viewing",
  date: "",
  time: "",
  notes: "",
  status: "scheduled",
};

const getTomorrowDateString = () => {
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const year = tomorrow.getFullYear();
  const month = String(tomorrow.getMonth() + 1).padStart(2, "0");
  const day = String(tomorrow.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
};

const formatDisplayTime = (time) => {
  if (!time) return "Select a time";
  const [hours, minutes] = time.split(":").map(Number);
  const suffix = hours >= 12 ? "PM" : "AM";
  const hour12 = hours % 12 || 12;
  return `${hour12}:${String(minutes).padStart(2, "0")} ${suffix}`;
};

const buildAppointmentDateTime = (date, time) => {
  if (!date || !time) return null;
  return new Date(`${date}T${time}:00`);
};

const isWorkingHours = (time) => {
  if (!time) return false;
  const [hours, minutes] = time.split(":").map(Number);
  return minutes === 0 && hours >= 9 && hours < 17;
};

const AddAppointment = () => {
  const navigate = useNavigate();
  const [appointment, setAppointment] = useState(initialAppointment);
  const [leads, setLeads] = useState([]);
  const [vehicles, setVehicles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [availableSlots, setAvailableSlots] = useState([]);
  const [slotsLoading, setSlotsLoading] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        const [leadsRes, vehiclesRes] = await Promise.all([
          api.get("/leads"),
          api.get("/vehicles"),
        ]);
        setLeads(Array.isArray(leadsRes.data) ? leadsRes.data : []);
        setVehicles(
          (Array.isArray(vehiclesRes.data) ? vehiclesRes.data : []).filter(
            (vehicle) => vehicle.status === "available"
          )
        );
      } catch (err) {
        setError(err.response?.data?.message || "Failed to load leads and vehicles");
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  useEffect(() => {
    const loadSlots = async () => {
      if (!appointment.date) {
        setAvailableSlots([]);
        return;
      }

      try {
        setSlotsLoading(true);
        const res = await api.get(`/appointments/available-slots/${appointment.date}`);
        setAvailableSlots(res.data?.slots || []);
      } catch (err) {
        setAvailableSlots([]);
        setError(err.response?.data?.message || "Failed to load available sessions");
      } finally {
        setSlotsLoading(false);
      }
    };

    loadSlots();
  }, [appointment.date]);

  const selectedLead = useMemo(
    () => leads.find((lead) => lead._id === appointment.lead),
    [leads, appointment.lead]
  );

  const selectedVehicle = useMemo(
    () => vehicles.find((vehicle) => vehicle._id === appointment.vehicle),
    [vehicles, appointment.vehicle]
  );

  const appointmentPreview = useMemo(
    () => buildAppointmentDateTime(appointment.date, appointment.time),
    [appointment.date, appointment.time]
  );

  const handleChange = (e) => {
    const { name, value } = e.target;
    setAppointment((current) => ({
      ...current,
      [name]: value,
      ...(name === "date" ? { time: "" } : {}),
    }));

    if (error) {
      setError("");
    }
  };

  const validateAppointment = () => {
    const appointmentDateTime = buildAppointmentDateTime(
      appointment.date,
      appointment.time
    );

    if (!appointment.lead || !appointment.vehicle || !appointment.date || !appointment.time) {
      return "Please complete all required appointment details";
    }

    if (!appointmentDateTime || Number.isNaN(appointmentDateTime.getTime())) {
      return "Please enter a valid appointment date and time";
    }

    if (appointmentDateTime <= new Date()) {
      return "Appointments can only be created for future dates and times";
    }

    if (!isWorkingHours(appointment.time)) {
      return "Appointments must be scheduled between 9:00 AM and 5:00 PM";
    }

    return "";
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const validationError = validateAppointment();
    if (validationError) {
      setError(validationError);
      return;
    }

    try {
      setSaving(true);
      setError("");
      await api.post("/appointments/add", {
        ...appointment,
        status: "scheduled",
      });
      navigate("/appointments");
    } catch (err) {
      setError(err.response?.data?.message || "Error adding appointment");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div
      style={{
        minHeight: "100%",
        background:
          "radial-gradient(circle at top left, rgba(194, 154, 82, 0.18), transparent 28%), linear-gradient(180deg, #f8f4eb 0%, #f2ede3 52%, #ece5da 100%)",
        padding: "32px 20px 48px",
      }}
    >
      <div style={{ maxWidth: "1200px", margin: "0 auto" }}>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "minmax(0, 1.3fr) minmax(320px, 0.7fr)",
            gap: "24px",
            alignItems: "stretch",
          }}
        >
          <div
            style={{
              background:
                "linear-gradient(135deg, rgba(14, 22, 34, 0.98) 0%, rgba(28, 43, 58, 0.92) 58%, rgba(92, 74, 46, 0.88) 100%)",
              borderRadius: "28px",
              padding: "36px",
              color: "#f8f4eb",
              boxShadow: "0 24px 70px rgba(15, 20, 25, 0.24)",
              position: "relative",
              overflow: "hidden",
            }}
          >
            <div
              style={{
                position: "absolute",
                top: "-80px",
                right: "-40px",
                width: "220px",
                height: "220px",
                borderRadius: "50%",
                background: "radial-gradient(circle, rgba(212, 177, 112, 0.26), transparent 70%)",
              }}
            />
            <div
              style={{
                position: "relative",
                zIndex: 1,
                display: "flex",
                flexDirection: "column",
                gap: "16px",
              }}
            >
              <div
                style={{
                  display: "inline-flex",
                  alignItems: "center",
                  gap: "10px",
                  width: "fit-content",
                  padding: "8px 14px",
                  borderRadius: "999px",
                  border: "1px solid rgba(255,255,255,0.12)",
                  background: "rgba(255,255,255,0.06)",
                  fontSize: "12px",
                  letterSpacing: "0.18em",
                  textTransform: "uppercase",
                }}
              >
                Concierge Booking
              </div>
              <div style={{ fontSize: "40px", fontWeight: 800, lineHeight: 1.1 }}>
                Create a premium appointment experience
              </div>
              <div
                style={{
                  maxWidth: "620px",
                  color: "rgba(248, 244, 235, 0.82)",
                  fontSize: "16px",
                  lineHeight: 1.7,
                }}
              >
                Schedule showroom visits and test drives with a polished workflow that
                feels tailored to high-value customers from the first interaction.
              </div>
              <div
                style={{
                  display: "grid",
                  gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",
                  gap: "12px",
                  marginTop: "8px",
                }}
              >
                {[
                  { label: "Booking Window", value: "Future dates only" },
                  { label: "Working Hours", value: "9:00 AM - 5:00 PM" },
                  { label: "Slot Format", value: "8 hourly sessions" },
                  { label: "Session Capacity", value: "Based on available staff" },
                ].map((item) => (
                  <div
                    key={item.label}
                    style={{
                      borderRadius: "18px",
                      padding: "16px 18px",
                      background: "rgba(255,255,255,0.08)",
                      border: "1px solid rgba(255,255,255,0.08)",
                    }}
                  >
                    <div
                      style={{
                        fontSize: "11px",
                        textTransform: "uppercase",
                        letterSpacing: "0.12em",
                        color: "rgba(248,244,235,0.62)",
                        marginBottom: "6px",
                      }}
                    >
                      {item.label}
                    </div>
                    <div style={{ fontSize: "15px", fontWeight: 600 }}>{item.value}</div>
                  </div>
                ))}
              </div>
            </div>
          </div>

          <div
            style={{
              background: "rgba(255,255,255,0.76)",
              backdropFilter: "blur(14px)",
              border: "1px solid rgba(15, 20, 25, 0.08)",
              borderRadius: "28px",
              padding: "28px",
              boxShadow: "0 22px 60px rgba(71, 57, 33, 0.12)",
            }}
          >
            <div style={{ fontSize: "13px", letterSpacing: "0.14em", textTransform: "uppercase", color: "#8b6b36", marginBottom: "10px" }}>
              Appointment Summary
            </div>
            <div style={{ fontSize: "28px", fontWeight: 800, color: "#16202b", marginBottom: "18px" }}>
              {selectedLead?.name || "Customer not selected"}
            </div>
            <div style={{ display: "grid", gap: "12px" }}>
              {[
                {
                  label: "Vehicle",
                  value: selectedVehicle
                    ? `${selectedVehicle.brand} ${selectedVehicle.type || selectedVehicle.model || ""}`.trim()
                    : "Choose a vehicle",
                },
                {
                  label: "Appointment Type",
                  value: appointment.appointmentType.replace("_", " "),
                },
                {
                  label: "Schedule",
                  value:
                    appointmentPreview && !Number.isNaN(appointmentPreview.getTime())
                      ? appointmentPreview.toLocaleString("en-US", {
                          weekday: "short",
                          month: "short",
                          day: "numeric",
                          year: "numeric",
                          hour: "numeric",
                          minute: "2-digit",
                        })
                      : "Select date and time",
                },
                {
                  label: "Status",
                  value: "Scheduled",
                },
              ].map((item) => (
                <div
                  key={item.label}
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    gap: "16px",
                    padding: "14px 16px",
                    borderRadius: "16px",
                    background: "rgba(248, 244, 235, 0.95)",
                    border: "1px solid rgba(22, 32, 43, 0.06)",
                  }}
                >
                  <span style={{ color: "#6e6251", fontSize: "13px", fontWeight: 600 }}>{item.label}</span>
                  <span style={{ color: "#16202b", fontSize: "14px", fontWeight: 700, textTransform: item.label === "Appointment Type" ? "capitalize" : "none" }}>
                    {item.value}
                  </span>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div
          style={{
            marginTop: "24px",
            background: "rgba(255,255,255,0.8)",
            backdropFilter: "blur(16px)",
            borderRadius: "30px",
            border: "1px solid rgba(15, 20, 25, 0.08)",
            boxShadow: "0 28px 80px rgba(71, 57, 33, 0.12)",
            overflow: "hidden",
          }}
        >
          <div
            style={{
              padding: "28px 32px",
              borderBottom: "1px solid rgba(15, 20, 25, 0.08)",
              display: "flex",
              justifyContent: "space-between",
              gap: "16px",
              flexWrap: "wrap",
              alignItems: "center",
            }}
          >
            <div>
              <div style={{ fontSize: "30px", fontWeight: 800, color: "#16202b", marginBottom: "6px" }}>
                Add Appointment
              </div>
              <div style={{ color: "#6e6251", fontSize: "15px" }}>
                Curate a polished booking with premium timing controls and cleaner customer context.
              </div>
            </div>
            <button type="button" onClick={() => navigate("/appointments")} className="btn" style={{ minWidth: "140px" }}>
              Back to List
            </button>
          </div>

          <form onSubmit={handleSubmit} style={{ padding: "32px" }}>
            {error ? (
              <div
                style={{
                  marginBottom: "24px",
                  padding: "14px 16px",
                  borderRadius: "16px",
                  border: "1px solid rgba(185, 28, 28, 0.18)",
                  background: "rgba(254, 242, 242, 0.95)",
                  color: "#b91c1c",
                  fontWeight: 600,
                }}
              >
                {error}
              </div>
            ) : null}

            <div
              style={{
                display: "grid",
                gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))",
                gap: "22px",
              }}
            >
              <SectionCard title="Client Details" subtitle="Choose the lead and vehicle for this premium visit">
                <Field label="Lead">
                  <select
                    className="select"
                    name="lead"
                    value={appointment.lead}
                    onChange={handleChange}
                    required
                    disabled={loading || saving}
                    style={fieldStyle}
                  >
                    <option value="">Select lead</option>
                    {leads.map((lead) => (
                      <option key={lead._id} value={lead._id}>
                        {lead.name}
                      </option>
                    ))}
                  </select>
                </Field>

                <Field label="Vehicle">
                  <select
                    className="select"
                    name="vehicle"
                    value={appointment.vehicle}
                    onChange={handleChange}
                    required
                    disabled={loading || saving}
                    style={fieldStyle}
                  >
                    <option value="">Select vehicle</option>
                    {vehicles.map((vehicle) => (
                      <option key={vehicle._id} value={vehicle._id}>
                        {`${vehicle.brand} ${vehicle.type || vehicle.model || ""}`.trim()}
                      </option>
                    ))}
                  </select>
                </Field>
              </SectionCard>

              <SectionCard title="Schedule" subtitle="Appointments must be booked in advance during business hours">
                <Field label="Date">
                  <input
                    className="input"
                    type="date"
                    name="date"
                    value={appointment.date}
                    onChange={handleChange}
                    min={getTomorrowDateString()}
                    required
                    disabled={saving}
                    style={fieldStyle}
                  />
                </Field>

                <Field label="Available Sessions">
                  {slotsLoading ? (
                    <div style={slotInfoStyle}>Checking hourly availability...</div>
                  ) : appointment.date ? (
                    availableSlots.length > 0 ? (
                      <div style={slotGridStyle}>
                        {availableSlots.map((slot) => {
                          const disabled = slot.availableStaffCount === 0;
                          const selected = appointment.time === slot.time;

                          return (
                            <button
                              key={slot.time}
                              type="button"
                              onClick={() =>
                                !disabled &&
                                setAppointment((current) => ({ ...current, time: slot.time }))
                              }
                              disabled={disabled || saving}
                              style={{
                                ...slotButtonStyle,
                                ...(selected ? selectedSlotButtonStyle : {}),
                                ...(disabled ? disabledSlotButtonStyle : {}),
                              }}
                            >
                              <span>{formatDisplayTime(slot.time)}</span>
                              <small>{slot.availableStaffCount} staff free</small>
                            </button>
                          );
                        })}
                      </div>
                    ) : (
                      <div style={slotInfoStyle}>No sessions are available on this date.</div>
                    )
                  ) : (
                    <div style={slotInfoStyle}>Choose a future date to load available hourly sessions.</div>
                  )}
                </Field>

                <div
                  style={{
                    padding: "14px 16px",
                    borderRadius: "16px",
                    background: "linear-gradient(135deg, rgba(194,154,82,0.12), rgba(22,32,43,0.04))",
                    color: "#5c4a2e",
                    fontSize: "13px",
                    lineHeight: 1.6,
                  }}
                >
                  Available booking window: future dates only, from <strong>9:00 AM</strong> to <strong>5:00 PM</strong>, in <strong>8 one-hour sessions</strong>. Each hour can be booked up to the number of available staff members.
                </div>
              </SectionCard>

              <SectionCard title="Experience Type" subtitle="Match the appointment to the customer journey">
                <Field label="Appointment Type">
                  <select
                    className="select"
                    name="appointmentType"
                    value={appointment.appointmentType}
                    onChange={handleChange}
                    disabled={saving}
                    style={fieldStyle}
                  >
                    <option value="viewing">Viewing</option>
                    <option value="test_drive">Test Drive</option>
                    <option value="follow_up">Follow Up</option>
                  </select>
                </Field>

                <Field label="Current Status">
                  <input
                    className="input"
                    type="text"
                    value="Scheduled"
                    readOnly
                    style={{ ...fieldStyle, background: "#f3eee5", color: "#6e6251", cursor: "not-allowed" }}
                  />
                </Field>
              </SectionCard>

              <SectionCard title="Notes" subtitle="Capture preferences, concerns, or any white-glove requests">
                <Field label="Internal Notes">
                  <textarea
                    className="textarea"
                    name="notes"
                    value={appointment.notes}
                    onChange={handleChange}
                    placeholder="Add showroom preferences, preparation notes, or customer expectations"
                    rows={7}
                    disabled={saving}
                    style={{ ...fieldStyle, resize: "vertical", minHeight: "180px" }}
                  />
                </Field>
              </SectionCard>
            </div>

            <div
              style={{
                marginTop: "28px",
                display: "flex",
                justifyContent: "space-between",
                gap: "16px",
                flexWrap: "wrap",
                alignItems: "center",
              }}
            >
              <div style={{ color: "#6e6251", fontSize: "14px" }}>
                Preferred slot: <strong style={{ color: "#16202b" }}>{formatDisplayTime(appointment.time)}</strong>
              </div>
              <div style={{ display: "flex", gap: "12px", flexWrap: "wrap" }}>
                <button type="button" className="btn" onClick={() => navigate("/appointments")} disabled={saving}>
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={saving || loading}
                  style={{
                    border: "none",
                    borderRadius: "999px",
                    padding: "14px 24px",
                    minWidth: "200px",
                    fontSize: "14px",
                    fontWeight: 700,
                    letterSpacing: "0.03em",
                    cursor: saving ? "not-allowed" : "pointer",
                    color: "#fffdf8",
                    background:
                      "linear-gradient(135deg, #182433 0%, #2e485f 50%, #b28a49 100%)",
                    boxShadow: "0 16px 30px rgba(24, 36, 51, 0.26)",
                    opacity: saving ? 0.72 : 1,
                  }}
                >
                  {saving ? "Saving Appointment..." : "Create Appointment"}
                </button>
              </div>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

function SectionCard({ title, subtitle, children }) {
  return (
    <div
      style={{
        padding: "24px",
        borderRadius: "24px",
        background: "linear-gradient(180deg, rgba(255,255,255,0.98), rgba(248,244,235,0.92))",
        border: "1px solid rgba(15, 20, 25, 0.06)",
        boxShadow: "inset 0 1px 0 rgba(255,255,255,0.7)",
      }}
    >
      <div style={{ marginBottom: "18px" }}>
        <div style={{ fontSize: "20px", fontWeight: 800, color: "#16202b", marginBottom: "6px" }}>
          {title}
        </div>
        <div style={{ fontSize: "13px", color: "#7a6c59", lineHeight: 1.6 }}>{subtitle}</div>
      </div>
      <div style={{ display: "grid", gap: "16px" }}>{children}</div>
    </div>
  );
}

function Field({ label, children }) {
  return (
    <label style={{ display: "grid", gap: "8px" }}>
      <span style={{ fontSize: "13px", fontWeight: 700, color: "#3f3424", letterSpacing: "0.01em" }}>
        {label}
      </span>
      {children}
    </label>
  );
}

const fieldStyle = {
  width: "100%",
  borderRadius: "16px",
  border: "1px solid rgba(22, 32, 43, 0.1)",
  background: "rgba(255,255,255,0.95)",
  padding: "14px 16px",
  fontSize: "14px",
  color: "#16202b",
  boxSizing: "border-box",
  boxShadow: "0 1px 0 rgba(255,255,255,0.8) inset",
};

const slotGridStyle = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fit, minmax(150px, 1fr))",
  gap: "12px",
};

const slotButtonStyle = {
  display: "grid",
  gap: "6px",
  padding: "14px 12px",
  borderRadius: "16px",
  border: "1px solid rgba(22, 32, 43, 0.08)",
  background: "rgba(255,255,255,0.96)",
  color: "#16202b",
  cursor: "pointer",
  textAlign: "left",
  boxShadow: "0 10px 24px rgba(22, 32, 43, 0.06)",
};

const selectedSlotButtonStyle = {
  background: "linear-gradient(135deg, #16202b 0%, #2e485f 55%, #b28a49 100%)",
  color: "#fffdf8",
  border: "1px solid rgba(22, 32, 43, 0.2)",
};

const disabledSlotButtonStyle = {
  cursor: "not-allowed",
  opacity: 0.42,
  boxShadow: "none",
};

const slotInfoStyle = {
  padding: "14px 16px",
  borderRadius: "16px",
  background: "rgba(248, 244, 235, 0.95)",
  color: "#6e6251",
  fontSize: "13px",
  lineHeight: 1.6,
};

export default AddAppointment;
